// Store refresh token in Redis with 1-year TTL
// ============================================================

async function storeRefreshToken(token, data) {
  const key = refreshTokenKey(token);
  const payload = JSON.stringify({
    ...data,
    created_at: Date.now(),
    expires_at: Date.now() + CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS * 1000,
  });

  // Store the refresh token with TTL
  await redis.setex(key, CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS, payload);

  // Track refresh tokens per user (for revocation)
  await redis.sadd(userRefreshTokensKey(data.user_id), token);
}

async function getRefreshToken(token) {
  const key = refreshTokenKey(token);
  const data = await redis.get(key);
  if (!data) return null;

  const parsed = JSON.parse(data);

  // Check expiration
  if (parsed.expires_at && Date.now() > parsed.expires_at) {
    await revokeRefreshToken(token, parsed.user_id);
    return null;
  }

  return parsed;
}

async function revokeRefreshToken(token, userId) {
  const key = refreshTokenKey(token);
  await redis.del(key);
  if (userId) {
    await redis.srem(userRefreshTokensKey(userId), token);
  }
}

async function revokeAllUserRefreshTokens(userId) {
  const tokens = await redis.smembers(userRefreshTokensKey(userId));
  const pipeline = redis.pipeline();
  for (const token of tokens) {
    pipeline.del(refreshTokenKey(token));
  }
  pipeline.del(userRefreshTokensKey(userId));
  await pipeline.exec();
}

