app.post('/authorize', async (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state, username, password, action } = req.body;

  // Validate client
  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({
      error: 'invalid_client',
      error_description: 'Unknown client',
    });
  }

  const finalRedirectUri = redirect_uri || client.redirect_uris[0];

  // User denied
  if (action === 'deny') {
    const params = new URLSearchParams({ error: 'access_denied' });
    if (state) params.set('state', state);
    return res.redirect(`${finalRedirectUri}?${params.toString()}`);
  }

  // Authenticate user
  let authenticatedUser = null;
  for (const [, user] of users) {
    if (user.username === username) {
      const valid = await verifyPassword(password, user.password_hash);
      if (valid) {
        authenticatedUser = user;
      }
      break;
    }
  }

  if (!authenticatedUser) {
    return res.status(401).send(`
      <html><body>
        <h1>Authentication Failed</h1>
        <p>Invalid username or password.</p>
        <a href="javascript:history.back()">Try again</a>
      </body></html>
    `);
  }

  // Generate authorization code
  const code = generateAuthorizationCode();
  const requestedScopes = scope ? scope.split(' ').filter((s) => client.scopes.includes(s)) : client.scopes;

  await storeAuthorizationCode(code, {
    client_id: client_id,
    user_id: authenticatedUser.id,
    redirect_uri: finalRedirectUri,
    scope: requestedScopes.join(' '),
    created_at: Date.now(),
  });

  // Redirect back with code
  const params = new URLSearchParams({ code });
  if (state) params.set('state', state);
  res.redirect(`${finalRedirectUri}?${params.toString()}`);
});

